import React, { useState } from "react";
import { Link } from "react-router-dom";
import Layout from "../Layout";
import ListingTable from "../../components/ListingTable/ListingTable";
import useFetch from "../../hooks/useFetch";
import { adminOrdersList, adminDeleteOrder } from "../../api/orders";
import { SOMETHING_WENT_WRONG, showSnackbar, errorType } from "../../../utils";
import EditIcon from "@mui/icons-material/Edit";
import DeleteIcon from "@mui/icons-material/Delete";
import VisibilityIcon from "@mui/icons-material/Visibility";

const STATUS_COLORS = {
  pending: "badge-warning",
  confirmed: "badge-info",
  shipped: "badge-primary",
  delivered: "badge-success",
  cancelled: "badge-danger",
};

const OrdersList = () => {
  const { apiData, isLoading, refetch } = useFetch(adminOrdersList, {});
  const [deleting, setDeleting] = useState(null);

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this order? Inventory will be restored."))
      return;
    setDeleting(id);
    try {
      await adminDeleteOrder(id);
      refetch();
    } catch (e) {
      showSnackbar(e || SOMETHING_WENT_WRONG, errorType);
    } finally {
      setDeleting(null);
    }
  };

  const columns = [
    {
      name: "ID",
      selector: (row) => row.id,
      sortable: true,
      width: "70px",
    },
    {
      name: "Customer",
      selector: (row) => row.customer?.name || "—",
      sortable: true,
    },
    {
      name: "Items",
      cell: (row) => `${row.items?.length || 0} item(s)`,
    },
    {
      name: "Total",
      selector: (row) => `₹${row.total}`,
      sortable: true,
    },
    {
      name: "Status",
      cell: (row) => (
        <span
          className={`badge ${STATUS_COLORS[row.status] || "badge-secondary"}`}
        >
          {row.status}
        </span>
      ),
    },
    {
      name: "Date",
      selector: (row) => new Date(row.created_at).toLocaleDateString("en-IN"),
      sortable: true,
    },
    {
      name: "Actions",
      cell: (row) => (
        <div style={{ display: "flex", gap: 6 }}>
          <Link
            to={`/orders/${row.id}`}
            className="btn btn-info btn-sm action-btn"
          >
            <VisibilityIcon />
          </Link>
          <Link
            to={`/orders/${row.id}/edit`}
            className="btn btn-warning btn-sm action-btn"
          >
            <EditIcon />
          </Link>
          <button
            onClick={() => handleDelete(row.id)}
            disabled={deleting === row.id}
            className="btn btn-danger btn-sm action-btn"
          >
            <DeleteIcon />
          </button>
        </div>
      ),
    },
  ];

  return (
    <Layout>
      <div className="d-sm-flex align-items-center justify-content-between mb-4">
        <div>
          <h1 className="h3 mb-2 text-gray-800">Orders</h1>
          <p className="mb-4">Manage your orders</p>
        </div>
        <Link to="/orders/new" className="btn btn-primary">
          + Create Order
        </Link>
      </div>

      <div className="card shadow mb-4">
        <div className="card-body">
          {isLoading ? (
            <p>Loading orders...</p>
          ) : (
            <div className="table-responsive">
              {apiData?.length > 0 ? (
                <ListingTable
                  columns={columns}
                  data={apiData}
                  isLoading={isLoading}
                  filterColumn="customer"
                />
              ) : (
                <p>No orders found.</p>
              )}
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
};

export default OrdersList;
